\begin{lemma}
[Scalar compatibility of the tile comparison at an arbitrary open]
  \label{lem:tile_scalar_compat_genV}
  \lean{AlgebraicGeometry.tile_scalar_compat'}
  \uses{lem:modulesSpecToSheaf_smul_eq, lem:modulesRestrictBasicOpen_smul_eq_genV,
    lem:tile_section_ring_identity_genV}
  The general-open companion of Lemma~\ref{lem:tile_scalar_compat}. Let \(\mathcal{F}\) be a
  quasi-coherent \(\mathcal{O}_{\Spec R}\)-module, let \(g, r \in R\), let \(V \subseteq \Spec R_g\) be
  an \emph{arbitrary} open, and let \(x\) be a section of the affine tile \(\mathcal{F}_{(g)}\) over
  \(V\) --- equivalently, on the underlying carrier, a section of \(\mathcal{F}\) over the
  iterated-image open \(\iota(V)\). Then the native \(R\)-action of \(r\) on \(x\) coincides with the
  \(R_g\)-action of the localised scalar \(\lambda(r) \in R_g\) on \(x\):
  \[
    r \cdot x \;=\; \lambda(r) \cdot x,
    \qquad \lambda : R \to R_g \text{ the localisation map}.
  \]
  The instance at \(V = D(\bar f)\) is the scalar-tower compatibility \(R \to R_g\) at the \emph{target}
  open of the per-tile section localization (Lemma~\ref{lem:tile_section_localization}); the
  \(V = \top\) case is Lemma~\ref{lem:tile_scalar_compat}.
\end{lemma}
\begin{proof}
  \uses{lem:modulesSpecToSheaf_smul_eq, lem:modulesRestrictBasicOpen_smul_eq_genV,
    lem:tile_section_ring_identity_genV}
  The same argument as Lemma~\ref{lem:tile_scalar_compat}, now at an arbitrary open \(V\). By
  Lemma~\ref{lem:modulesSpecToSheaf_smul_eq} the native \(R\)-action of \(r\) on \(x\) reduces to a
  structure-sheaf scalar action, and by Lemma~\ref{lem:modulesRestrictBasicOpen_smul_eq_genV} the
  \(R_g\)-action of \(\lambda(r)\) on \(x\) (as a tile section over \(V\)) reduces to a structure-sheaf
  scalar action on the same underlying carrier. The two scalars then agree by the morphism-level ring
  identity of Lemma~\ref{lem:tile_section_ring_identity_genV} evaluated at \(r\).
\end{proof}

